// ─────────────────────────────────────────────
// Detect overdue tasks per group, build chase msgs
// Skip group if no overdue.
// ─────────────────────────────────────────────
const norm = (v) => String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const groupsResp = $('Fetch Active Groups').item.json;
const groupsList = Array.isArray(groupsResp) ? groupsResp : (groupsResp?.data || []);
const FALLBACK = [
  { wa_chat_id: '120363426390515923@g.us', label: 'Angel Fly', context_key: 'angelfly' },
  { wa_chat_id: '120363420996892188@g.us', label: 'Garlic',    context_key: 'garlic' },
  { wa_chat_id: '120363422948599063@g.us', label: 'Ernesto',   context_key: 'ernesto' }
];
const groups = groupsList.length ? groupsList : FALLBACK;

const collect = (items) => {
  const all = [];
  for (const it of items) {
    const j = it.json;
    if (Array.isArray(j)) j.forEach(r => r?.id && all.push(r));
    else if (Array.isArray(j?.data)) j.data.forEach(r => r?.id && all.push(r));
    else if (j?.id) all.push(j);
  }
  return all;
};
const tasks = collect($('Fetch All Tasks').all());

const today = new Date(Date.now() - 3*3600000).toISOString().slice(0,10);
const isOpen = (s) => !['done','closed','cancelled','resolved','completed'].includes(norm(s));
const groupMatch = (t, ctx) => {
  const blob = norm(t.project_name||'') + ' ' + norm(t.client_name||'');
  if (ctx==='garlic')   return /garlic|gnl/.test(blob);
  if (ctx==='ernesto')  return /ernesto/.test(blob);
  if (ctx==='angelfly') return /angel\s*fly|cockpit/.test(blob);
  return true;
};

const daysOverdue = (deadline) => {
  if (!deadline) return 0;
  const d = new Date(deadline.slice(0,10) + 'T12:00:00Z');
  const t = new Date(today + 'T12:00:00Z');
  return Math.max(0, Math.round((t - d) / 86400000));
};

// Tone variants — Jarvis gets progressively saltier
const toneByDays = (d) => {
  if (d <= 1) return '👀';
  if (d <= 3) return '🕸️';
  if (d <= 7) return '🚨';
  return '💀';
};

const openings = [
  '👀 *Galera, alerta de atraso:*',
  '⏰ *Olha aí, time — coisa parada:*',
  '🚨 *Atenção, papo de cobrança:*',
  '⚠️ *Pequeno aviso de PM-chato:*',
  '🕵️ *Detective Jarvis na área. Achei isto:*'
];
const closings = [
  '\n\nQuem tá com qual? Atualiza o status que eu páro de encher. 🙏',
  '\n\nMe avisa se algum precisa de prazo novo ou tá bloqueado.',
  '\n\nSe alguma já tá feita, marca como done no Cockpit que eu paro de cobrar.',
  '\n\nPM mode: cobrança feita. Bola pra vocês.'
];

const results = [];
for (const g of groups) {
  const ctx = g.context_key || g.context;
  const label = g.label || ctx;
  const chatId = g.wa_chat_id;

  const overdue = tasks
    .filter(t => isOpen(t.status) && t.deadline && t.deadline.slice(0,10) < today && groupMatch(t, ctx))
    .map(t => ({ ...t, dOver: daysOverdue(t.deadline) }))
    .sort((a,b) => b.dOver - a.dOver);

  if (!overdue.length) continue; // pula grupo sem atrasados

  let msg = openings[Math.floor(Math.random()*openings.length)] + '\n';

  for (const t of overdue.slice(0, 8)) {
    const owner = t.assigned_to_name ? '👤 ' + t.assigned_to_name : '👤 _sem dono_';
    const proj = t.project_name ? ' (' + t.project_name + ')' : '';
    const emoji = toneByDays(t.dOver);
    msg += '\n' + emoji + ' *' + (t.title || 'sem título') + '*' + proj;
    msg += '\n   ' + owner + ' · prazo ' + (t.deadline||'').slice(0,10) + ' · *' + t.dOver + 'd atrasada*';
  }

  if (overdue.length > 8) msg += '\n\n_… e mais ' + (overdue.length-8) + ' atrasadas._';

  msg += closings[Math.floor(Math.random()*closings.length)];

  results.push({ json: { number: chatId, text: msg, count: overdue.length } });
}

if (!results.length) return [{ json: { skip: true, reason: 'no_overdue_anywhere' } }];

return results;
